import json
import os
import psycopg2
import psycopg2.extras


DB_HOST = os.environ.get('DB_HOST', 'internal-db.us-east-1.rds.amazonaws.com')
DB_PORT = os.environ.get('DB_PORT', '5432')
DB_NAME = os.environ.get('DB_NAME', 'production')
DB_USER = os.environ.get('DB_USER', 'admin')
DB_PASSWORD = os.environ.get('DB_PASSWORD', 'password')

connection = None


def get_connection():
    global connection
    if connection is None or connection.closed:
        connection = psycopg2.connect(
            host=DB_HOST,
            port=DB_PORT,
            dbname=DB_NAME,
            user=DB_USER,
            password=DB_PASSWORD,
            connect_timeout=5
        )
        connection.autocommit = True
    return connection


def execute_query(query, params=None):
    conn = get_connection()
    try:
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cursor:
            cursor.execute(query, params)
            if cursor.description:
                rows = cursor.fetchall()
                results = [dict(row) for row in rows]
                return results
            else:
                return {"rowcount": cursor.rowcount}
    except (psycopg2.OperationalError, psycopg2.InterfaceError):
        global connection
        connection = None
        conn = get_connection()
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cursor:
            cursor.execute(query, params)
            if cursor.description:
                rows = cursor.fetchall()
                results = [dict(row) for row in rows]
                return results
            else:
                return {"rowcount": cursor.rowcount}


def default_serializer(obj):
    from datetime import datetime, date, time
    from decimal import Decimal
    import uuid

    if isinstance(obj, (datetime, date, time)):
        return obj.isoformat()
    elif isinstance(obj, Decimal):
        return float(obj)
    elif isinstance(obj, uuid.UUID):
        return str(obj)
    elif isinstance(obj, bytes):
        return obj.decode('utf-8', errors='replace')
    raise TypeError(f"Object of type {type(obj).__name__} is not JSON serializable")


def lambda_handler(event, context):
    try:
        query = event.get('query')
        params = event.get('params')

        if not query:
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({
                    'error': 'Missing required field: query'
                })
            }

        query_lower = query.strip().lower()
        allowed_statements = ('select', 'insert', 'update', 'delete', 'with')
        if not query_lower.startswith(allowed_statements):
            return {
                'statusCode': 400,
                'headers': {'Content-Type': 'application/json'},
                'body': json.dumps({
                    'error': 'Only SELECT, INSERT, UPDATE, DELETE, and WITH statements are allowed'
                })
            }

        results = execute_query(query, params)

        response_body = {
            'success': True,
            'data': results,
            'count': len(results) if isinstance(results, list) else None
        }

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps(response_body, default=default_serializer)
        }

    except psycopg2.ProgrammingError as e:
        return {
            'statusCode': 400,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({
                'success': False,
                'error': 'Query error',
                'message': str(e)
            })
        }

    except psycopg2.OperationalError as e:
        return {
            'statusCode': 503,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({
                'success': False,
                'error': 'Database connection error',
                'message': str(e)
            })
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({
                'success': False,
                'error': 'Internal server error',
                'message': str(e)
            })
        }